# Define SNS Topic ARN
sns_topic_arn = os.environ['SNS_TOPIC_ARN']

# Create CloudWatch Logger
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    try:
        # Get the object from S3
        s3 = boto3.client('s3')
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        key = event['Records'][0]['s3']['object']['key']

        # Process the image
        # For this example, we'll just copy the object to a new location in S3
        s3.copy_object(Bucket=bucket_name, Key=key, CopySource={'Bucket': bucket_name, 'Key': key})

        # Send notification via SNS
        sns = boto3.client('sns')
        message = f"Image processed: {key}"
        sns.publish(TopicArn=sns_topic_arn, Message=message)

        # Log to CloudWatch
        logger.info(f"Processed image: {key}")

    except ClientError as e:
        logger.error(e)
        raise

    return {
        'statusCode': 200,
        'statusMessage': 'OK'
    }